                HashMap<String, String> headers = new HashMap<String, String>();
                headers.put("t", iQiyiInterface.getEncryptTimestamp());
                headers.put("sign", iQiyiInterface.getSign());

                // MyLog.d(TAG, "headers=" + headers);
                return headers;
            }
        };

